// Get the input text
const inputText = $input.first().json.subtitles[0].srt;

// List of filler words to remove
const fillerWords = [
  'um', 'uh', 'umm', 'uhh', 'err', 'ah', 'like', 'you know', 
  'sort of', 'kind of', 'basically', 'actually', 'literally',
  'i mean', 'you see', 'right?', 'okay?', 'alright',
  'so yeah', 'yeah so', 'well um', 'well uh'
];

// Function to clean the text
function cleanTranscript(text) {
  let cleaned = text;

  // Remove filler words (case insensitive, with word boundaries)
  fillerWords.forEach(filler => {
    const regex = new RegExp(`\\b${filler}\\b[,\\s]*`, 'gi');
    cleaned = cleaned.replace(regex, ' ');
  });

  // Remove repeated words (e.g., "so so so" → "so")
  cleaned = cleaned.replace(/\b(\w+)(\s+\1\b)+/gi, '$1');

  // Fix multiple spaces
  cleaned = cleaned.replace(/\s{2,}/g, ' ');

  // Fix spacing around punctuation
  cleaned = cleaned.replace(/\s+([.,!?;:])/g, '$1');
  cleaned = cleaned.replace(/([.,!?;:])\s*/g, '$1 ');

  // Remove space before newlines
  cleaned = cleaned.replace(/\s+\n/g, '\n');

  // Trim
  cleaned = cleaned.trim();

  return cleaned;
}

// Clean the transcript
const cleanedText = cleanTranscript(inputText);

// Return the result
return [{
  json: {
    cleanedTranscript: cleanedText,
    originalLength: inputText.length,
    cleanedLength: cleanedText.length,
    reductionPercentage: Math.round((1 - cleanedText.length / inputText.length) * 100)
  }
}];

const transcripts = items[0].json.data.transcripts;

return transcripts.map(t => ({
  json: {
    transcript_id: t.id,
    title: t.title,
    date: t.date
  }
}));

